import { VscOpenPreview } from "react-icons/vsc";
import React, { useState, useEffect } from "react";
import { IoCloseCircleOutline } from "react-icons/io5";
import {
  ModalContainer,
  CloseButton,
  ModalBtn,
  ButtonGroup,
} from "../../../Styles/DataRoomStyle.js";
import CurrencyFormatter from "../../../../components/CurrencyFormatter";
import axios from "axios";
import { API_BASE_URL } from "../../../../config/config.js";

const InvestorInvestmentHistory = ({ onClose, recordViewData, id }) => {
  var apiURL_History = API_BASE_URL + "api/user/investmenthistory/";
  const storedUsername = localStorage.getItem("SignatoryLoginData");
  const userLogin = JSON.parse(storedUsername);

  const [investmentData, setInvestmentData] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    getInvestmentHistoryWithWarrantlist();
  }, []);

  const getInvestmentHistoryWithWarrantlist = async () => {
    setLoading(true);
    const formData = {
      company_id: userLogin.companies[0].id,
      investor_id: id,
      round_id: recordViewData?.id,
      investorrequest_company_id: recordViewData?.investor_request_id
    };
    try {
      const generateRes = await axios.post(
        apiURL_History + "getInvestmentHistoryWithWarrantlist",
        formData,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
          },
        }
      );
      console.log(generateRes.data.results);
      if (generateRes.data.results && generateRes.data.results.length > 0) {
        setInvestmentData(generateRes.data.results[0]);
      }
    } catch (err) {
      console.error("Error generating summary", err);
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return "N/A";
    return new Date(dateString).toLocaleDateString("en-US", {
      year: "numeric",
      month: "short",
      day: "numeric",
    });
  };

  const getStatusBadgeColor = (status) => {
    switch (status) {
      case "exercised":
        return "bg-success";
      case "pending":
        return "bg-warning";
      case "expired":
        return "bg-danger";
      default:
        return "bg-secondary";
    }
  };

  return (
    <div className="main_popup-overlay">
      <ModalContainer style={{ maxWidth: '85vw', maxHeight: '85vh', overflow: 'auto' }}>
        <CloseButton onClick={onClose}>×</CloseButton>

        <div className="p-4">
          {/* Header Section */}
          <div className="d-flex align-items-center justify-content-between mb-4 pb-3 border-bottom">
            <div className="d-flex align-items-center gap-3">
              <div className="bg-primary bg-opacity-10 p-3 rounded-circle">
                <VscOpenPreview size={24} className="text-primary" />
              </div>
              <div>
                <h3 className="mb-0 fw-bold text-dark">Investment History</h3>
                <p className="text-muted mb-0 small">Warrant and investment details</p>
              </div>
            </div>
            <button
              type="button"
              className="bg-transparent text-secondary p-1 border-0 hover-danger"
              onClick={onClose}
              style={{ transition: "all 0.2s" }}
            >
              <IoCloseCircleOutline size={28} />
            </button>
          </div>

          {loading ? (
            <div className="text-center py-5">
              <div className="spinner-border text-primary" role="status">
                <span className="visually-hidden">Loading...</span>
              </div>
              <p className="mt-3 text-muted">Loading investment data...</p>
            </div>
          ) : investmentData ? (
            <div className="investment-details">
              {/* Investment Details Card */}
              <div className="card shadow-sm border-0 mb-4">
                <div className="card-header bg-white border-0 pt-4 pb-0">
                  <h5 className="fw-bold mb-0">
                    <span className="border-start border-primary border-3 ps-3">Investment Details</span>
                  </h5>
                </div>
                <div className="card-body">
                  <div className="row g-4">
                    <div className="col-md-12">
                      <div className="bg-light rounded-3 p-4">
                        <div className="row align-items-center">
                          <div className="col-md-6">
                            <div className="text-center text-md-start mb-3 mb-md-0">
                              <small className="text-muted text-uppercase fw-semibold d-block mb-2">Total Shares</small>
                              <h3 className="mb-0 fw-bold text-primary">
                                <CurrencyFormatter amount={investmentData.shares} />
                              </h3>
                            </div>
                          </div>
                          <div className="col-md-6">
                            <div className="border-start border-2 ps-4">
                              <div className="row">
                                <div className="col-6">
                                  <small className="text-muted d-block mb-1">New Shares</small>
                                  <strong className="fs-5">
                                    <CurrencyFormatter amount={investmentData.new_shares} />
                                  </strong>
                                </div>
                                <div className="col-6">
                                  <small className="text-muted d-block mb-1">Percentage</small>
                                  <strong className="fs-5">{investmentData.percentage_formatted}</strong>
                                </div>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Warrant Details Card */}
              {investmentData.warrant_id && (
                <div className="card shadow-sm border-0 mb-4">
                  <div className="card-header bg-white border-0 pt-4 pb-0">
                    <h5 className="fw-bold mb-0">
                      <span className="border-start border-primary border-3 ps-3">Warrant Details</span>
                    </h5>
                  </div>
                  <div className="card-body">
                    <div className="row g-4">
                      <div className="col-md-6">
                        <div className="bg-light rounded-3 p-3 h-100">
                          <div className="d-flex align-items-center justify-content-between mb-2">
                            <small className="text-muted fw-semibold">Warrant ID</small>
                            <span className="badge bg-dark px-3 py-2 rounded-pill">
                              #{investmentData.warrant_id}
                            </span>
                          </div>
                          <hr className="my-2" />
                          <div className="mt-2">
                            <small className="text-muted d-block mb-1">Coverage Percentage</small>
                            <h4 className="mb-0 fw-bold text-primary">{investmentData.warrant_coverage_percentage}%</h4>
                          </div>
                        </div>
                      </div>
                      <div className="col-md-6">
                        <div className="bg-light rounded-3 p-3 h-100">
                          <div className="mb-3">
                            <small className="text-muted d-block mb-2">Exercise Status</small>
                            <span className={`badge ${getStatusBadgeColor(investmentData.exercise_status)} px-3 py-2 fs-6 rounded-pill`}>
                              {investmentData.exercise_status?.toUpperCase()}
                            </span>
                          </div>
                          <div>
                            <small className="text-muted d-block mb-2">Warrant Status</small>
                            <span className={`badge ${getStatusBadgeColor(investmentData.warrant_status)} px-3 py-2 fs-6 rounded-pill`}>
                              {investmentData.warrant_status?.toUpperCase()}
                            </span>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              )}

              {/* Important Dates Card */}
              <div className="card shadow-sm border-0">
                <div className="card-header bg-white border-0 pt-4 pb-0">
                  <h5 className="fw-bold mb-0">
                    <span className="border-start border-primary border-3 ps-3">Important Dates</span>
                  </h5>
                </div>
                <div className="card-body">
                  <div className="row g-4">
                    <div className="col-md-6">
                      <div className="bg-gradient-to-r from-info to-info bg-opacity-10 rounded-3 p-4 text-center">
                        <div className="mb-2">
                          <i className="bi bi-calendar-event fs-2 text-info"></i>
                        </div>
                        <small className="text-muted text-uppercase fw-semibold d-block mb-2">Issued Date</small>
                        <h5 className="mb-0 fw-bold">{formatDate(investmentData.issued_date)}</h5>
                      </div>
                    </div>
                    <div className="col-md-6">
                      <div className="bg-gradient-to-r from-warning to-warning bg-opacity-10 rounded-3 p-4 text-center">
                        <div className="mb-2">
                          <i className="bi bi-calendar-x fs-2 text-warning"></i>
                        </div>
                        <small className="text-muted text-uppercase fw-semibold d-block mb-2">Expiration Date</small>
                        <h5 className="mb-0 fw-bold">{formatDate(investmentData.expiration_date)}</h5>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="text-center py-5">
              <div className="bg-light rounded-circle p-4 d-inline-block mb-3">
                <VscOpenPreview size={48} className="text-muted" />
              </div>
              <h5 className="text-muted">No investment history found</h5>
              <p className="text-muted small">No data available for this investment</p>
            </div>
          )}
        </div>

        <ButtonGroup className="d-flex gap-2 mt-4">
          <ModalBtn
            onClick={onClose}
            className="close_btn w-fit px-4 py-2 rounded-pill"
            style={{ background: "#f0f0f0", border: "none", fontWeight: "500" }}
          >
            Close
          </ModalBtn>
        </ButtonGroup>
      </ModalContainer>
    </div>
  );
};

export default InvestorInvestmentHistory;